def day_3(inst, number_of_santas):

  deliveries = {}
  santas     = []
  cnt        = 0

  # spawn santas
  for i in range (0,number_of_santas):
    santas.append(Santa())

  # start deliveries
  deliveries[0,0] = number_of_santas

  for i in inst:
    s = cnt % number_of_santas
    santas[s].updatepos(i)
    x,y = santas[s].getpos()
    deliveries[x,y] = 1
    cnt += 1

  return { "houses" : len(deliveries) }

