def next_house(loc, d):
    result = loc[:]
    if d == '<':   # west
        result[0] += -1
    elif d == '>': # east
        result[0] += 1
    elif d == '^': # north
        result[1] += 1
    elif d == 'v': # south
        result[1] += -1
    return result

