      return False

  return True

def improved_nice_string(str):
  # Check for double pair
  if not re.search(r'(.)(.).*\1\2', str): #some wild boobies appear
    return False

  # letter repeat
  if not re.search(r'(.).\1', str):
    return False

  return True


