def memoize(f):
    memo = {}
    def helper(x):
        if x not in memo:
            memo[x] = f(x)
        return memo[x]
    return helper


class Operator:
  def __init__(self, a=None):
    self.a = a

  def get_result(self):
    return self.a

class Connection(Operator):
    def __init__(self, a=None):
      self.a = a
    def get_result(self):
      return d[self.a].get_result()

class AndOperator(Operator):
  def __init__(self, a=None, b=None):
    self.a = a
    self.b = b
  @memoize
  def get_result(self):
    return (d[self.a].get_result() & d[self.b].get_result())

class NotOperator(Operator):
  def __init__(self, a=None):
    self.a = a
  def get_result(self):
    return ~d[self.a].get_result()

class OROperator(Operator):
  def __init__(self, a=None, b=None):
    self.a = a
    self.b = b
  def get_result(self):
    return (d[self.a].get_result() | d[self.b].get_result())

class XOROperator(Operator):
  def __init__(self, a=None, b=None):
    self.a = bin(a)
    self.b = bin(b)
  def get_result(self):
    return (d[self.a].get_result() ^ d[self.b].get_result())

class LeftShift(Operator):
  def __init__(self, a=None, b=None):
    self.a = a
    self.b = b
  def get_result(self):
    return d[self.a].get_result() << d[self.b].get_result()

class RightShift(Operator):
  def __init__(self, a=None, b=None):
    self.a = a
    self.b = b
  def get_result(self):
    return d[self.a].get_result() >> d[self.b].get_result()

def fillOperator(op, a, b):
    return {
        'AND': AndOperator(a,b),
        'OR': OROperator(a,b),
        'RSHIFT': RightShift(a,b),
        'LSHIFT': LeftShift(a,b)
    }[op]

