def parse_expression(ex):
    data = ex.strip().split()
    if len(data) == 1:
        return value_of(data[0])
    if len(data) == 2:
        n = value_of(data[1])
        return n ^ 65535
    a, e, b = data
    a, b = value_of(a), value_of(b)
    if e == 'AND':
        return a & b
    if e == 'OR':
        return a | b
    if e == 'LSHIFT':
        return a << b
    if e == 'RSHIFT':
