def cookie_score(recipe, ingredients, calGoal=None):
    s = ingredients * recipe
    if calGoal and s.loc['calories'].sum() != calGoal:
        return 0
    s = s.drop('calories').sum(axis=1)
    s[s < 0] = 0
    return s.prod()


