    with open('year_2015_day_19.txt') as fin:
        replacements, starter = parse(fin.read())
    print(count_molecules(starter, replacements))


def part_two():
    with open('year_2015_day_19.txt') as fin:
        replacements, target = parse(fin.read())
    print(steps_to_generate(target, replacements))


