    output = ""
    for char in data:
        if char == '\n':
            x, y = position
            output += str(KEYPAD[x][y])
            continue
        idx = INDEXES[char]
        diff = DIFFS[char]
        newpos = position.copy()
        newpos[idx] += diff
        x, y = newpos
        try:
            if KEYPAD[x][y] == ' ' or x not in VALID or y not in VALID:
                continue
            else:
                position = newpos
        except IndexError:
