import regex as re

def supernets_and_hypernets(s):
    seqs = re.split(r'\[|\]', s)
    return seqs[::2], seqs[1::2]

def has_abba(s):
    return any(a != b for a, b in re.findall(r'(.)(.)\2\1', s, overlapped=True))


