    for line in s.split('\n'):
        supernets, hypernets = supernets_and_hypernets(line)
        babs = [bab for supernet in supernets
                for bab in babs_for_abas(supernet)]
        if any(bab in hypernet for bab in babs
               for hypernet in hypernets):
