def deco(string):
    match = re.search(r'\(\d+x\d+\)', string)

    if not match:
        return string
    else:
        match_numbers = re.findall(r'\d+', match.group())
        c, t = (int(n) for n in match_numbers)
        s, e = match.start(), match.end() 
        return string[0:s] + t * string[e:e+c] + deco(string[e+c:])

