	if (dif > 0):
		branchNum = branchesWeight.index(max(branchesWeight))
	else:
		branchNum = branchesWeight.index(min(branchesWeight))

	branchToCheck = currentNode.children[branchNum]
	return findWrongProgram(branchToCheck, dif)



