            "<" => pred_var < pred_val,
            "<=" => pred_var <= pred_val,
            "!=" => pred_var != pred_val,
            _ => panic!("unknown predicate {}", &splits[5])
        };

        if pred_success {
            *mem.entry(splits[0].to_string()).or_insert(0) += amount;
            max = max.max(mem[splits[0]]); // wew
        }
    }

