import math

def tuple_add(t1, t2):
	return (t1[0] + t2[0], t1[1] + t2[1], t1[2] + t2[2])

def tuple_abs_sum(t):
	return abs(t[0]) + abs(t[1]) + abs(t[2])

def solve_quad_int(a, b, c):
	if a != 0:
		D2 = b * b - 4 * a * c
		if D2 < 0:
			return (False, None)
		D = int(math.sqrt(D2) + 0.5)
		if D ** 2 != D2:
			return (False, None)
		x1 = -b - D
		x2 = -b + D
		a2 = 2 * a
		solutions = set()
		if x1 % a2 == 0:
			solutions.add(x1 / a2)
		if x2 % a2 == 0:
			solutions.add(x2 / a2)
		return (True, solutions)
	elif b != 0:
		if c % b == 0:
			return (True, set([ - c / b]))
		return (False, None)
	else:
		if a == 0:
			return (True, None)
		return (False, None)

class Particle:
	def __init__(self, line):
		chunks = line.strip().split(', ')
		ret = []
		for ch in chunks:
			pars = ch.split('=')[1]
			ret.append(tuple([int(x) for x in pars.lstrip('<').rstrip('>').split(',')]))
		self.p = ret[0]
		self.v = ret[1]
		self.a = ret[2]	

	def move(self):
		v = tuple_add(v, a)
		p = tuple_add(p, v)

	def compare(self, other):
		if tuple_abs_sum(self.a) != tuple_abs_sum(other.a):
			return tuple_abs_sum(self.a) < tuple_abs_sum(other.a)
		if sum(self.v) != sum(other.v):
			return sum(self.v) < sum(other.v)
		return sum(self.p) < sum(other.p)

	def collides(self, other):
		ret = None
		for d in xrange(3):
			da = self.a[d] - other.a[d]
			dv = self.v[d] - other.v[d]
			ds = self.p[d] - other.p[d]
			ok, solutions = solve_quad_int(da, 2 * dv + da, 2 * ds)
			if not ok:
				return None
			if solutions:
				if ret == None:
					ret = solutions
				else:
					ret &= solutions
		if ret == None:
			return 0
		ret = filter(lambda x: x >= 0, ret)		
		return min(ret) if ret else None


