using namespace std;

typedef vector<vector<char>> Matrix;

int traverseGrid(Matrix &grid, const int iterations)
{
	typedef enum direction {U = 0, R, D, L} Direction;
	int num_directions = 4;

	int bursts = 0;
	int y = grid.size() / 2;
	int x = grid[0].size() / 2;
	Direction dir = U;

	for (int i = 0; i < iterations; i++) {
		if (grid[y][x] == '.') {
			grid[y][x] = 'W';
			dir = (Direction)(((dir - 1) % num_directions + num_directions) % num_directions);
		} else if (grid[y][x] == 'W') {
			grid[y][x] = '#';
			bursts++;
		} else if (grid[y][x] == '#') {
			grid[y][x] = 'F';
			dir = (Direction)((dir + 1) % num_directions);
		} else {
			grid[y][x] = '.';
			dir = (Direction)((dir + 2) % num_directions);
		}

		if (dir == U) y -= 1;
		else if (dir == R) x += 1;
		else if (dir == D) y += 1;
		else x -= 1;
	}

	return bursts;
}

