    unused = list(filter(lambda b: b not in bridge and b[::-1] not in bridge, blocks))
    for block in unused:
        if bridge[-1][1] == block[0]:
            yield bridge + [block]
        elif bridge[-1][1] == block[1]:
            yield bridge + [block[::-1]]

