        bottom_left=(parsed_claim.offset[0],parsed_claim.offset[1] + parsed_claim.size[1] - 1),
        bottom_right=(parsed_claim.offset[0] + parsed_claim.size[0] - 1,parsed_claim.offset[1] + parsed_claim.size[1] - 1)
