def claims_overlap(claim1,claim2):
    return not (claim1.bottom_right[1] < claim2.top_left[1] 
                or claim1.top_left[1] > claim2.bottom_right[1] 
                or claim1.bottom_right[0] < claim2.top_left[0] 
                or claim1.top_left[0] > claim2.bottom_right[0]
            )

