def power_level(x, y, serial_id):
    rack_id = x + 10
    level = rack_id * y
    level += serial_id
    level *= rack_id
    level = (level // 100) % 10
    return level - 5

def power_sum(grid, x, y, s=3):
    return sum(grid[x_][y_] for x_ in range(x, x+s) for y_ in range(y, y+s))

