class Car:
    def __init__(self, char, coords):
        self.xdir = 0
        self.ydir = 0
        if char == '>':
            self.xdir = 1
        elif char == '<':
            self.xdir = -1
        elif char == 'v':
            self.ydir = 1
        elif char == '^':
            self.ydir = -1
        else:
            raise RuntimeError('invalid character for a car ' + char)
        self.coords = coords
        self.turns = 0
        self.crashed = False

    def move(self):
        self.coords = (self.coords[0] + self.xdir, self.coords[1] + self.ydir)
        next_location = grid[self.coords[1]][self.coords[0]]
        if next_location == '/':
            if self.ydir == 0:
                self.left()
            else:
                self.right()
        elif next_location == '\\':
            if self.ydir == 0:
                self.right()
            else:
                self.left()
        elif next_location == '+':
            self.turn()

    def turn(self):
        next_turn = self.turns % 3
        if next_turn == 0:
            self.left()
        elif next_turn == 1:
            pass
        elif next_turn == 2:
            self.right()
        self.turns += 1

    def left(self):
        self.xdir, self.ydir = self.ydir, self.xdir * -1

    def right(self):
        self.xdir, self.ydir = self.ydir * -1, self.xdir


cars = set()
