def list_map(f, s):
    return list(map(f, s))

def addr(registers, a, b, c):
    result = registers[::]
    result[c] = result[a] + result[b]
    return result

def addi(registers, a, b, c):
    result = registers[::]
    result[c] = result[a] + b
    return result

def mulr(registers, a, b, c):
    result = registers[::]
    result[c] = result[a] * result[b]
    return result

def muli(registers, a, b, c):
    result = registers[::]
    result[c] = result[a] * b
    return result

def banr(registers, a, b, c):
    result = registers[::]
    result[c] = result[a] & result[b]
    return result

def bani(registers, a, b, c):
    result = registers[::]
    result[c] = result[a] & b
    return result

def borr(registers, a, b, c):
