def execute(opmap, machine_code, r1):
    n, a, b, c = machine_code
    mnemonic = opmap[n]

    r2 = r1[:]

    if   mnemonic == 'addr':
        r2[c] = r1[a] + r1[b]
    elif mnemonic == 'addi':
        r2[c] = r1[a] + b
    elif mnemonic == 'mulr':
        r2[c] = r1[a] * r1[b]
    elif mnemonic == 'muli':
        r2[c] = r1[a] * b
    elif mnemonic == 'banr':
        r2[c] = r1[a] & r1[b]
    elif mnemonic == 'bani':
        r2[c] = r1[a] & b
    elif mnemonic == 'borr':
        r2[c] = r1[a] | r1[b]
    elif mnemonic == 'bori':
        r2[c] = r1[a] | b
    elif mnemonic == 'setr':
        r2[c] = r1[a]
    elif mnemonic == 'seti':
        r2[c] = a
    elif mnemonic == 'gtir':
        r2[c] = 1 if a > r1[b] else 0
    elif mnemonic == 'gtri':
        r2[c] = 1 if r1[a] > b else 0
    elif mnemonic == 'gtrr':
        r2[c] = 1 if r1[a] > r1[b] else 0
    elif mnemonic == 'eqir':
        r2[c] = 1 if a == r1[b] else 0
    elif mnemonic == 'eqri':
        r2[c] = 1 if r1[a] == b else 0
    elif mnemonic == 'eqrr':
        r2[c] = 1 if r1[a] == r1[b] else 0

    return r2

def simplify(ops):
    definitive = {}

    while len(definitive) != 16:
        added = []
        for num, candidates in ops.items():
            if len(candidates) == 1:
                assert num not in definitive

                definitive[num] = candidates.pop()
                added.append(num)

        for k in added:
            ops.pop(k)
            op = definitive[k]

            for kk in ops:
                if op in ops[kk]:
                    ops[kk].remove(op)

                    if len(ops[kk]) == 0:
                        ops.pop(kk)

    return definitive

