def magic(n):
    global a

    def z(x):
        return ''.join(c for r in x for c in r)

    h = {z(a): 0}

    p = -1
    for t in range(1, n + 1):
        b = []
        for i in range(len(a)):
            r = []
            for j in range(len(a[i])):
                if g(i, j) == '.':
