def getDivisors(n):
 if n == 1:
  return [1]

 max = n
 num = 2
 result = [1, n]

 while num < max:
  if not n % num:
   if num != n/num:
    result.extend([num, n//num])
   else:
    result.append(num)
   max = n//num
  num += 1
 return sorted(result)

