    for p in ss.split("; "):
        if len(p) == 0:
            continue
        mul = 1
        if p[:4] == "weak":
            mul = 2
            p = p[8:]
        elif p[:6] == "immune":
            mul = 0
            p = p[10:]
        for dt in p.split("&"):
            tp[types.index(dt)] = mul
    return tp

