class Path:
    def __init__(self, moves):
        self.node_set = set() # set of reachable coordinates
        self.node_map = dict() # map of reachable coordinates to the amount of steps required to reach them

        def get_nodes(path, origin, steps):
            if not path:
                return
            move = path.pop(0)
            if move[0] == 'R':
                nxt = lambda n: ((origin[0] + n, origin[1]), steps)
            elif move[0] == 'L':
                nxt = lambda n: ((origin[0] - n, origin[1]), steps)
            elif move[0] == 'U':
                nxt = lambda n: ((origin[0], origin[1] + n), steps)
            elif move[0] == 'D':
                nxt = lambda n: ((origin[0], origin[1] - n), steps)
            for n in range(int(move[1:])):
                steps = steps + 1
                node = nxt(n+1)
                self.node_set.add(node[0])
                if self.node_map.get(node[0], float('+inf')) > steps:
                    self.node_map[node[0]] = steps
            get_nodes(path, node[0], steps)

        get_nodes(moves, (0, 0), 0)

    def get_closest_intersection(self, other):
        intersection = self.node_set.intersection(other.node_set)
        min_distance = float('+inf')
        for node in intersection:
            min_distance = min(min_distance, self.node_map[node] + other.node_map[node])
        return min_distance

