        elif op == 3:
            p[p[ip+1]] = yield
            ip += 2
        elif op == 4:
            yield p[p[ip+1]]
            ip += 2
        elif op == 5:
            a = p[ip + 1] if cmd // 100 % 10 == 1 else p[p[ip + 1]]
            if a != 0:
                ip = p[ip + 2] if cmd // 1000 % 10 == 1 else p[p[ip + 2]]
            else:
                ip += 3
        elif op == 6:
            a = p[ip + 1] if cmd // 100 % 10 == 1 else p[p[ip + 1]]
            if a == 0:
