from collections import defaultdict

def p2(ns, target):
  li = sorted(ns)
  l = 0
  r = len(li) - 1
  while l < r:
    s = li[l] + li[r]
    if s == target:
      return li[l] * li[r]
    elif s > target:
      r -= 1
    else:
      l += 1

def p3(ns, target):
  # dict
  # Key: sum
  # Value: list<tuple<set_indices, tuple_numbers>>
  nij = defaultdict(list)
  for i, ni in enumerate(ns):
    for j, nj in enumerate(ns):
      if i >= j:
        continue
      nij[ni+nj].append((set([i, j]), (ni, nj)))

  # For each third number, see if there exists a pair where the third number is unused
  # If so, return the product
  for k, nk in enumerate(ns):
    diff = target - nk
    for sum_tuple in nij[diff]:
      already_used = sum_tuple[0]
      if k in already_used:
        continue
      ni = sum_tuple[1][0]
      nj = sum_tuple[1][1]
      return ni*nj*nk

