from __future__ import annotations

from dataclasses import dataclass
from enum import auto, Enum
from typing import List, Tuple


class ChallengePart(Enum):
    FIRST = auto()
    SECOND = auto()


@dataclass
class PasswordCondition:
    first: int
    second: int


@dataclass
class PasswordEntry:
    condition: PasswordCondition
    char: str
    password: str

    def check_password_v1(self) -> bool:
        return self.condition.first <= self.password.count(self.char) <= self.condition.second

    def check_password_v2(self) -> bool:
        try:
            return (
                (self.password[self.condition.first - 1] == self.char) ^
                (self.password[self.condition.second - 1] == self.char)
            )
        except IndexError:
            return False

    @classmethod
    def deserialize_from_password_entry(cls, password_entry: str) -> PasswordEntry:
        condition, char, password = password_entry.split()

        return cls(
            condition=PasswordCondition(
                first=int(condition.split("-")[0]),
                second=int(condition.split("-")[1])
            ),
            char=char[0],
            password=password
        )


def check_passwords(password_entries: List[PasswordEntry], part: ChallengePart) -> int:
    count = 0
    if part == ChallengePart.FIRST:
        for entry in password_entries:
            if entry.check_password_v1():
                count += 1
    elif part == ChallengePart.SECOND:
        for entry in password_entries:
            if entry.check_password_v2():
                count += 1

    return count


def main() -> Tuple[int, int]:
    with open('year_2020_day_2.txt', "r") as f:
        password_entries = [
            PasswordEntry.deserialize_from_password_entry(line) for line in f.readlines()
        ]

    return (
        check_passwords(password_entries, ChallengePart.FIRST),
        check_passwords(password_entries, ChallengePart.SECOND)
    )


if __name__ == "__main__":
    print(main())

