import math

def part_1(data: list, slope: tuple) -> int:
    trees = 0
    right, down = (0, 0)
    while down < len(data):
        if data[down][right % len(data[0])] == '#':
            trees += 1
        right += slope[0]
        down += slope[1]
    return trees

def part_2(data: list, slopes: tuple) -> int:
    return math.prod(part_1(data, slope) for slope in slopes)

