from typing import List


def find_encountered_trees(data: List[str], run: int, rise: int) -> int:
    x, y = 0, 0
    depth, width = len(data), len(data[0])
    forest = [line * (ceil(max([(depth/rise), (width/run)]))) for line in data]
    trees_encountered = 0
    while y < len(forest):
        if forest[y][x] == "#":
            trees_encountered += 1
        x += run
        y += rise
    return trees_encountered


def part_a(file_location) -> int:
    with open('year_2020_day_3.txt', "r") as f:
        data = [line.strip() for line in f]
    return find_encountered_trees(data, 3, 1)


def part_b(file_location) -> int:
