def read_input(day, type):
    data = {}
    i = 0
    fn = 'day' + str(day) + '.txt'
    if type == 'day4':
        data[0] = {'byr': 0, 'iyr': 0, 'eyr': 0, 'hgt': 0, 'hcl': 0, 'ecl': 0, 'pid': 0, 'cid': 0}
    with open('year_2020_day_4.txt', 'r') as f:
        for line in f:
            if type == 'int':
                data[i] = int(line)
                i = i + 1
            elif type == 'list':
                data[i] = line.split()
                i = i + 1
            elif type == 'day4':
                if line == '\n':
                    i = i + 1
                    data[i] = {'byr':0, 'iyr':0, 'eyr':0, 'hgt':0, 'hcl':0, 'ecl':0, 'pid':0, 'cid':0}
                else:
                    record = line.split()
                    for rec in record:
                        fields = rec.split(':')
                        data[i][fields[0]] = fields[1]
            else:
                data[i] = line.strip('\n')
                i = i + 1
    return data

