def build_dic(obj_string, dict_keys, pass_test_bool=False):
    '''obj_string == "key:value key:value key:value..."'''
    dict_build={}
    for key_val_str in obj_string.split():
        key_val_list=key_val_str.split(':')
        key=key_val_list[0]
        val=key_val_list[1]
        if key in dict_keys:
