def year_validator(start, end):
    return lambda s: s.isdigit() and len(s) == 4 and start <= int(s) <= end

def re_validator(pattern):
    return lambda s: pattern.match(s) is not None

height_pattern = re.compile(r'^(\d+)(cm|in)$')
def is_valid_height(s):
    match = height_pattern.match(s)
    if match:
        n, unit = match.group(1), match.group(2)
        if unit == 'cm':
            return 150 <= int(n) <= 193
        else:
            return 59 <= int(n) <= 76
    return False


