"""Day 4 of Advent of Code 2020 Solution"""
import re


VALID_FIELDS = {'byr', 'iyr', 'eyr', 'hgt', 'hcl', 'ecl', 'pid'}
License = dict[str, str]


def parse_license_data(file_location) -> list[License]:
    with open('year_2020_day_4.txt', "r") as f:
        data = []
        license = {}
        for line in f:
            current_line = line.strip()
            if current_line:
                for key_val in current_line.strip().split(" "):
                    key, val = key_val.split(":")
                    license[key] = val
            else:
                data.append(license.copy())
                license.clear()
        data.append(license)
    return data


def is_valid_byr(byr: str) -> bool:
    """Validate birth year"""
    return (len(byr) == 4) and (1920 <= int(byr) <= 2002)


def is_valid_iyr(iyr: str) -> bool:
    """Validate issue year"""
    return (len(iyr) == 4) and (2010 <= int(iyr) <= 2020)


def is_valid_eyr(eyr: str) -> bool:
    """Validate expiration year"""
    return (len(eyr) == 4) and (2020 <= int(eyr) <= 2030)


def is_valid_hgt(hgt: str) -> bool:
    """Validate height"""
    height_pattern = r"(\d+)(in|cm)"
    height_validation = {
        'cm': lambda x: 150 <= int(x) <= 193,
        'in': lambda x: 59 <= int(x) <= 76
    }
    if match := re.search(height_pattern, hgt):
        height = match.group(1)
        unit = match.group(2)
        return height_validation[unit](height)
    return False

def is_valid_hcl(hcl: str) -> bool:
    """Validate hair color"""
    return bool(re.match(r"#[0-9a-f]{6}", hcl))


def is_valid_ecl(ecl: str) -> bool:
    """Validate eye color"""
    valid_eye_colors = {'amb', 'blu', 'brn', 'gry', 'grn', 'hzl', 'oth'}
    return ecl in valid_eye_colors


def is_valid_pid(pid: str) -> bool:
    """Validate passport ID"""
    return bool(re.match(r"\b[0-9]{9}\b", pid))


def has_required_fields(license: License) -> bool:
    """License contains all required fields"""
    return VALID_FIELDS.issubset(set(license.keys()))


def all_license_fields_valid(license: License) -> bool:
    validator = {'byr': is_valid_byr,
                 'iyr': is_valid_iyr,
                 'eyr': is_valid_eyr,
                 'hgt': is_valid_hgt,
                 'hcl': is_valid_hcl,
                 'ecl': is_valid_ecl,
                 'pid': is_valid_pid,
                  }
    return all([validator[k](license[k]) for k in validator])


def is_valid_license(license: License) -> bool:
    if has_required_fields(license) and all_license_fields_valid(license):
        return True
    return False


def part_a(file_location):
    data = parse_license_data(file_location)
    n_valid = 0
    for license in data:
        if has_required_fields(license):
            n_valid += 1
        else:
            continue
    return n_valid


def part_b(file_location):
    data = parse_license_data(file_location)
    n_valid = 0
    for license in data:
        if is_valid_license(license):
            n_valid += 1
        else:
            continue
    return n_valid


if __name__ == '__main__':
    print(part_a(r"data\day4.txt"))
    print(part_b(r"data\day4.txt"))

from __future__ import annotations

from dataclasses import dataclass
import re
from typing import Any, Dict, Optional, Tuple


@dataclass
class PassportField:
    value: Optional[Any]

    def validate(self) -> bool:
        raise NotImplementedError


@dataclass
class BirthYear(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                return 1920 <= int(self.value) <= 2002
            except ValueError:
                return False

        return False


@dataclass
class IssueYear(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                return 2010 <= int(self.value) <= 2020
            except ValueError:
                return False

        return False


@dataclass
class ExpirationYear(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                return 2010 <= int(self.value) <= 2030
            except ValueError:
                return False

        return False


@dataclass
class Height(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                height = int(self.value[:-2])
                return (
                    ((150 <= height <= 193) and "cm" in self.value) or
                    ((59 <= height <= 76) and "in" in self.value)
                )
            except ValueError:
                return False

        return False


@dataclass
class HairColor(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            return re.match(r"\#[0-9a-f]{6}", self.value) is not None

        return False


@dataclass
class EyeColor(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            return any(
                color == self.value for color in ["amb", "blu", "brn", "gry", "grn", "hzl", "oth"]
            )

        return False


@dataclass
class PassportID(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                int(self.value)
                return len(self.value) == 9
            except ValueError:
                return False

        return False


@dataclass
class CountryID(PassportField):
    def validate(self) -> bool:
        return True


@dataclass
class Passport:
    birth_year: BirthYear
    issue_year: IssueYear
    expiration_year: ExpirationYear
    height: Height
    hair_color: HairColor
    eye_color: EyeColor
    passport_id: PassportID
    country_id: CountryID

    def check_validity_v1(self) -> bool:
        for field in self.__dict__.values():
            if field.value is None and not isinstance(field, CountryID):
                return False

        return True

    def check_validity_v2(self) -> bool:
        for field in self.__dict__.values():
            if not field.validate():
                return False

        return True

    @classmethod
    def deserialize_from_input(cls, input_entry: Dict[str, str]) -> Passport:
        return cls(
            birth_year=BirthYear(input_entry.get("byr")),
            issue_year=IssueYear(input_entry.get("iyr")),
            expiration_year=ExpirationYear(input_entry.get("eyr")),
            height=Height(input_entry.get("hgt")),
            hair_color=HairColor(input_entry.get("hcl")),
            eye_color=EyeColor(input_entry.get("ecl")),
            passport_id=PassportID(input_entry.get("pid")),
            country_id=CountryID(input_entry.get("cid")),
        )


def main() -> Tuple[int, int]:
    with open('year_2020_day_4.txt', "r") as f:
        passport_entries_raw = [passport_entry.strip() for passport_entry in f.read().split("\n\n")]
        passport_entries_massaged = [
            [field.split(":") for field in passport_entry.split()] for
            passport_entry in passport_entries_raw
        ]

        passport_entries = [
            Passport.deserialize_from_input({field[0]: field[1] for field in passport_entry}) for
            passport_entry in passport_entries_massaged
        ]

        return (
            sum(passport_entry.check_validity_v1() for passport_entry in passport_entries),
            sum(passport_entry.check_validity_v2() for passport_entry in passport_entries)
        )


if __name__ == "__main__":
    print(main())

import re

def read_input(fname):
    with open('year_2020_day_4.txt', "r") as handle:
        records = [x.replace("\n", " ") for x in handle.read().split("\n\n")]
        return [parse_passport(rec) for rec in records]

def parse_passport(passport):
    fields = passport.replace("\n", " ").split(" ")
    return dict([tuple(x.split(":")) for x in fields if len(x) > 0])

def has_required_fields(passport):
    for r_field in ["byr", "iyr", "eyr", "hgt", "hcl", "ecl", "pid"]:
        if r_field not in passport.keys():
            return False
    return True

def validate_field(key, val):
    def _hgt_check(val):
        return (
            ("cm" in val and 150 <= int(val.replace("cm", "")) <= 193) or
            ("in" in val and 59 <= int(val.replace("in", "")) <= 76)
        )

    rules = {
        "byr": lambda x: 1920 <= int(x) <= 2002,
        "cid": lambda x: True,
        "ecl": lambda x: x in ["amb", "blu", "brn", "gry", "grn", "hzl", "oth"],
        "eyr": lambda x: 2020 <= int(x) <= 2030,
        "hcl": lambda x: bool(re.match(r"^#[a-fA-F0-9]{6}$", x)),
        "hgt": _hgt_check,
        "iyr": lambda x: 2010 <= int(x) <= 2020,
        "pid": lambda x: bool(re.match(r"^[0-9]{9}$", x)),
    }
    return key in rules.keys() and rules[key](val)

def is_valid_p2(passport):
    return (
        has_required_fields(passport) and
        all([validate_field(k, v) for (k, v) in passport.items()])
    )

def solve_p1(inp):
    return len([x for x in inp if has_required_fields(x)])

def solve_p2(inp):
    return len([x for x in inp if is_valid_p2(x)])

