def find_binary_partition(low, high, l_char, h_char, string):
    for char in string:
        mid = (low + high) // 2
        if char == l_char:
            high = mid
        elif char == h_char:
            low = mid + 1
    if low != high:
        print('ERROR')
        return -1
    return low


