def binary_partition(bsp, r):
    if r[0] == r[1]: return r[0]

    half = (r[1] + r[0]) // 2

    if bsp[0] in ['F', 'L']: return binary_partition(bsp[1:], (r[0], half))
    elif bsp[0] in ['B', 'R']: return binary_partition(bsp[1:], (half + 1, r[1]))


