from __future__ import annotations

from dataclasses import dataclass
from typing import List, Set, Tuple


@dataclass
class BoardingPass:
    row: int
    column: int
    seat_id: int

    @classmethod
    def deserialize_from_raw_input(cls, input_entry: str) -> BoardingPass:
        row = int(input_entry[:7].replace("F", "0").replace("B", "1"), base=2)
        column = int(input_entry[-3:].replace("L", "0").replace("R", "1"), base=2)

        return cls(
            row=row,
            column=column,
            seat_id=(row * 8) + column
        )


def find_highest_seat_id(boarding_passes: List[BoardingPass]) -> int:
    return max(boarding_pass.seat_id for boarding_pass in boarding_passes)


def find_lowest_seat_id(boarding_passes: List[BoardingPass]) -> int:
    return min(boarding_pass.seat_id for boarding_pass in boarding_passes)


def find_missing_seat_ids(boarding_passes: List[BoardingPass]) -> Set[int]:
    expected_seat_ids = set(
        range(
            find_lowest_seat_id(boarding_passes),
            find_highest_seat_id(boarding_passes) + 1
        )
    )
    actual_seat_ids = set(boarding_pass.seat_id for boarding_pass in boarding_passes)

    return expected_seat_ids - actual_seat_ids


def main() -> Tuple[int, int]:
    with open('year_2020_day_5.txt', "r") as f:
        boarding_passes = [
            BoardingPass.deserialize_from_raw_input(line.strip()) for line in f.readlines()
        ]

        # We only expect one missing seat, so pop from the set returned by find_missing_seat_ids.
        return find_highest_seat_id(boarding_passes), find_missing_seat_ids(boarding_passes).pop()


if __name__ == "__main__":
    print(main())

