def partition(upper, lower, id, index):
    if upper == lower:
        return upper
    if id[index] in "BR":
        # Take upper half of partition
        lower = (upper - lower) // 2 + lower + 1
    elif id[index] in "FL":
        # Take lower half of partition
        upper = (upper - lower) // 2 + lower

    index += 1
    return partition(upper, lower, id, index)


