def soln2(surveys):
    count = 0
    set_list = []
    for s in surveys:
        if s == "":
            common_answers = set_list[0].intersection(*set_list[1:])
            count += len(common_answers)
            set_list = []
        else:
            set_list.append(set(s))

    common_answers = set_list[0].intersection(*set_list[1:])
    count += len(common_answers)
    return count


