from dataclasses import dataclass
from typing import List, Set, Tuple


@dataclass
class CustomsForm:
    group_answers: Set[str]

    @classmethod
    def deserialize_from_raw_input_v1(cls, input_entry: str) -> CustomsForm:
        return cls(group_answers=set(input_entry.replace("\n", "")))

    @classmethod
    def deserialize_from_raw_input_v2(cls, input_entry: str) -> CustomsForm:
        return cls(
            group_answers=set.intersection(*[set(answers) for answers in input_entry.split()])
        )


def sum_of_customs_form_answers(customs_forms: List[CustomsForm]) -> int:
    return sum(len(customs_form.group_answers) for customs_form in customs_forms)


