import re

# A dict with all bags that should contain other bags
policies = dict()
# A set of all bags
allbags = set()

def read_input(f):
    f=open('year_2020_day_7.txt', "r")
    return f.read().split('\n')

def can_hold_shiny_gold(bag):
    if bag not in policies:
        return False
    if 'shiny gold' in policies[bag]:
        return True
    # if it's not directly in this policy, it could be in a child policy
    return any([can_hold_shiny_gold(child) for child in policies[bag]])

def amount_of_child_bags(bag):
    if bag not in policies:
        return 0
    # good old recursion
    return sum([ int(child[1])*(1+amount_of_child_bags(child[0])) for child in policies[bag].items()])

def solve(f, part="A"):
    policies_strings = read_input(f)

    #Parse all policies
    for pol in policies_strings:
        parent = re.findall(r"^([a-z\s?]+) bags?",pol.split("contain")[0])
        child = re.findall(r"([0-9]+)\s+([a-z]+\s+[a-z]+)",pol.split("contain")[1])

        # add child policies for this bag to the dict, and add parent to set
        if len(child) > 0:
            policies.update({parent[0]: {c[1] : c[0] for c in child}})
        allbags.add(parent[0])

    if part == "A":
        return sum([ 1 if can_hold_shiny_gold(bag) else 0 for bag in allbags])
    return amount_of_child_bags('shiny gold')

print(f'Part A: {solve("input.txt")}, Part B: {solve("input.txt", part="B")}')

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Tuple


@dataclass
class LuggageRule:
    bag_colour: str
    containment_rules: Set[str] = field(default_factory=set)
    can_contain: Set[str] = field(default_factory=set)
    contained_by: Set[str] = field(default_factory=set)

    def update_child_contained_by_rules(self, luggage_rules: Dict[str, LuggageRule]) -> None:
        for luggage_rule in [luggage_rules[bag_colour] for bag_colour in self.can_contain]:
            luggage_rule.contained_by.add(self.bag_colour)

    def list_parent_rules(
        self,
        luggage_rules: Dict[str, LuggageRule],
        seen_parents: Optional[Set[str]] = None
    ) -> Set[str]:

        parent_rules = self.contained_by
        if seen_parents is None:
            seen_parents = {self.bag_colour}
        else:
            seen_parents.add(self.bag_colour)

        for luggage_rule in [luggage_rules[bag_colour] for bag_colour in self.contained_by]:
            if luggage_rule.bag_colour not in seen_parents:
                parent_rules.update(luggage_rule.list_parent_rules(luggage_rules, seen_parents))

        return parent_rules

    def count_self_and_containing_bags(self, luggage_rules: Dict[str, LuggageRule]) -> int:
        if self.containment_rules:
            count = 1
            for bag_rule in self.containment_rules:
                multiple = int(bag_rule.split()[0])
                bag_colour = " ".join(bag_rule.split()[1:])
                count += multiple * luggage_rules[bag_colour].count_self_and_containing_bags(
                    luggage_rules
                )
            return count

        # A bag that can't contain anything else only counts itself.
        return 1

    def count_containing_bags(self, luggage_rules: Dict[str, LuggageRule]) -> int:
        return self.count_self_and_containing_bags(luggage_rules) - 1

    @classmethod
    def deserialize_from_raw_input(cls, input_entry: str) -> LuggageRule:
        # Remove the period at the end.
        bag_colour, containment_text = input_entry[:-1].split(" bags contain ")
        if "no other bags" not in containment_text:
            return cls(
                bag_colour=bag_colour,
                containment_rules=set(
                    # Remove 'bags/bag.' from each entry.
                    rule.split(" bag")[0] for rule in containment_text.split(", ")
                ),
                can_contain=set(
                    # Only take in the colours.
                    " ".join(bag_rule.split()[1:-1]) for bag_rule in containment_text.split(", ")
                )
            )

        return cls(
            bag_colour=bag_colour,
        )


def main() -> Tuple[int, int]:
    with open('year_2020_day_7.txt', "r") as f:
        luggage_rules: Dict[str, LuggageRule] = {}
        for line in f.readlines():
            luggage_rule = LuggageRule.deserialize_from_raw_input(line)
            luggage_rules[luggage_rule.bag_colour] = luggage_rule

        for luggage_rule in luggage_rules.values():
            luggage_rule.update_child_contained_by_rules(luggage_rules)

        return (
            len(luggage_rules["shiny gold"].list_parent_rules(luggage_rules)),
            luggage_rules["shiny gold"].count_containing_bags(luggage_rules)
        )


if __name__ == "__main__":
    print(main())

