from __future__ import annotations

from dataclasses import dataclass, field
from enum import Enum
from typing import List, Iterator, Tuple


class Operation(Enum):
    nop = "nop"
    acc = "acc"
    jmp = "jmp"


@dataclass
class Instruction:
    operation: Operation
    value: int
    seen: bool = field(default=False)

    @classmethod
    def deserialize_from_raw_input(cls, input_entry: str) -> Instruction:
        return cls(
            operation=Operation(input_entry.split()[0]),
            value=int(input_entry.split()[1])
        )


@dataclass
class InstructionList:
    instructions: List[Instruction]
    accumulator_value: int = field(default=0)
    position: int = field(default=0)

    def execute_instruction(self) -> None:
        instruction = self.instructions[self.position]

        if instruction.operation == Operation.nop:
            self.position += 1
            instruction.seen = True
            return

        if instruction.operation == Operation.acc:
            self.accumulator_value += instruction.value
            self.position += 1
            instruction.seen = True
            return

        if instruction.operation == Operation.jmp:
            self.position += instruction.value
            instruction.seen = True
            return

        raise NotImplementedError

    def execute_instructions(self) -> None:
        instruction = self.instructions[0]

        while not instruction.seen:
            self.execute_instruction()
            instruction = self.instructions[self.position]

    def execute_and_catch_termination(self) -> bool:
        try:
            self.execute_instructions()
        except IndexError:
            return self.position == len(self.instructions)

        # We land here if we encounter a loop.
        return False

    def reset(self) -> None:
        self.accumulator_value = 0
        self.position = 0
        for instruction in self:
            instruction.seen = False

    def __iter__(self) -> Iterator[Instruction]:
        return iter(instruction for instruction in self.instructions)


def flip_instruction(instruction: Instruction) -> None:
    if instruction.operation == Operation.nop:
        instruction.operation = Operation.jmp
    elif instruction.operation == Operation.jmp:
        instruction.operation = Operation.nop


def fix_corruption(instruction_list: InstructionList) -> int:
    for instruction in instruction_list:
        flip_instruction(instruction)

        if instruction_list.execute_and_catch_termination():
            return instruction_list.accumulator_value

        flip_instruction(instruction)
        instruction_list.reset()

    raise RuntimeError("Failed to fix corruption")


def main() -> Tuple[int, int]:
    with open('year_2020_day_8.txt', "r") as f:
        instruction_list = InstructionList(
            instructions=[Instruction.deserialize_from_raw_input(line) for line in f.readlines()]
        )

    instruction_list.execute_instructions()
    part_1 = instruction_list.accumulator_value

    instruction_list.reset()
    part_2 = fix_corruption(instruction_list)

    return part_1, part_2


