                    t = [getValue(lines,i-1,j-1), getValue(lines,i-1,j), getValue(lines,i-1,j+1),
                        getValue(lines,i  ,j-1),                         getValue(lines,i  ,j+1),
                        getValue(lines,i+1,j-1), getValue(lines,i+1,j), getValue(lines,i+1,j+1)]
                    if (t.count('#') == 0):
