		winner = c1 > c2
		if len(deck1) >= c1 and len(deck2) >= c2:
			winner = game(deck1[:c1], deck2[:c2])[0]
		if winner:
			deck1 = deck1 + [c1, c2]
		else:
			deck2 = deck2 + [c2, c1]
	if deck1:
		return (True, deck1)
	else:
		return (False, deck2)
