def filter_nums(nums, rating):
    pos = 0
    while len(nums) > 1:
        ones, zero = [], []
        for num in nums:
            if num[pos] == '1':
                ones.append(num)
            else:
                zero.append(num)
        pos += 1
        by_size = sorted((zero, ones), key=len)
        nums = by_size[1] if rating == 'O2' else by_size[0]
    return int(nums[0], 2)

