import re

def t(l):
    return list(zip(*l))


class Board:
    def __init__(self, strings):
        self.map = [None] * 100
        self.board = [[False for _ in range(5)] for _ in range(5)]
        numbers = [list(map(int, re.split(r"\s+", string.strip()))) for string in strings]
        for i in range(5):
            for j in range(5):
                self.map[numbers[i][j]] = (i, j)

    def mark(self, number):
        position = self.map[number]
        if position is not None:
            self.map[number] = None
            i, j = position
            self.board[i][j] = True

    def check(self):
        return any(all(r) for r in self.board) or any(all(c) for c in t(self.board))

    def sum_unused(self):
        total = 0
        for i, item in enumerate(self.map):
            if item is not None:
                total += i
        return total

    def __str__(self) -> str:
        return '\n'.join([' '.join(map(lambda x: 'X' if x else ' ',row)) for row in self.board])


