# Parses a single line of input and loads it into data structure(s)
def parse_input_line(s):
    left, right = s.split(' -> ')
    a_x, a_y = left.split(',')
    b_x, b_y = right.split(',')

    a_x = int(a_x)
    a_y = int(a_y)
    b_x = int(b_x)
    b_y = int(b_y)

    draw_line(a_x, a_y, b_x, b_y)

def draw_line(a_x, a_y, b_x, b_y):
    if a_x == b_x:
        draw_vertical_line(a_x, a_y, b_y)
    elif a_y == b_y:
        draw_horizontal_line(a_x, b_x, a_y)
    elif diagonals:
        draw_diagonal_line(a_x, a_y, b_x, b_y)

def draw_vertical_line(x, a_y, b_y):
    if a_y < b_y:
        lower_bound = a_y
        upper_bound = b_y + 1
    else:
        lower_bound = b_y
        upper_bound = a_y + 1
    for y in range(lower_bound, upper_bound):
        map[x][y] += 1
        if map[x][y] > 1:
            hazards.add((x, y))

def draw_horizontal_line(a_x, b_x, y):
    if a_x < b_x:
        lower_bound = a_x
        upper_bound = b_x + 1
    else:
        lower_bound = b_x
        upper_bound = a_x + 1
    for x in range(lower_bound, upper_bound):
        map[x][y] += 1
        if map[x][y] > 1:
            hazards.add((x, y))

def draw_diagonal_line(a_x, a_y, b_x, b_y):
    x = a_x
    y = a_y
    n = a_x - b_x
    if n < 0:
        n = -n
    n += 1
    if b_x < a_x:
        x_step = -1
    else:
        x_step = 1
    if b_y < a_y:
        y_step = -1
    else:
        y_step = 1
    for i in range(n):
        map[x][y] += 1
        if map[x][y] > 1:
            hazards.add((x, y))

        x += x_step
        y += y_step

