def get_vent_locations_on_line(x1, y1, x2, y2):
    dx = int(x2 > x1) - int(x2 < x1)  # -1|0|1
    dy = int(y2 > y1) - int(y2 < y1)
    return [(x1 + n * dx, y1 + n * dy) for n in range(max(abs(x2 - x1), abs(y2 - y1)) + 1)]


def find_line_overlaps(vent_lines):
    vent_locations = set()
