class Point:
def __init__(self, x, y) -> None:
    self._x = int(x)
    self._y = int(y)

def x(self) -> int:
    return self._x

def y(self) -> int:
    return self._y

def __str__(self) -> str:
    return "Point %d - %d"%(self.x(), self.y())

class Line:
def __init__(self, start : Point, end :Point) -> None:
    self._start = start
    self._end = end

def __str__(self) -> str:
    return "Line [%s] - [%s]"%(str(self._start), str(self._end))

def isVertical(self) -> bool:
    return self._start.x() == self._end.x()

def isHorizontal(self) -> bool:
    return self._start.y() == self._end.y()

def isStraight(self) -> bool:
    if self.isHorizontal() or self.isVertical():
        return True

def getPoints(self) -> Iterable:
    x_off = 0
    y_off = 0
    if self._start.x() < self._end.x():
        x_off = +1
    elif self._start.x() > self._end.x():
        x_off = -1
    if self._start.y() < self._end.y():
        y_off = +1
    elif self._start.y() > self._end.y():
        y_off = -1
    x = self._start.x()
    y = self._start.y()

    while(x != self._end.x() + x_off or y != self._end.y() + y_off):
        yield Point(x, y)
        x += x_off
        y += y_off

