def next_timer_state(timer):
    if timer >= 7:
        return timer - 1
    return (timer - 1) % 7


def spawn(timers, days_to_go):
    if days_to_go == 0:
        return timers
    return spawn(
        [next_timer_state(timer) for timer in timers] + [8 for timer in timers if timer == 0],
        days_to_go - 1,
    )


