    return sum(cost(abs(elem - val)) for elem in arr)


def fuel_cost2(data):
    window = int(len(data) * .1)
    m = round(mean(data))
    minim = sum_cost(data, m)
    for i in range(m - window, m + window):
        if (temp := sum_cost(data, i)) < minim:
            minim = temp
    return minim


