    for line in data:
        stack = []
        for char in line:
            if char in BRACKET_PAIRS.keys():
                stack.append(char)
            elif char in BRACKET_PAIRS.values():
                most_recent_open = stack.pop()
                if BRACKET_PAIRS[most_recent_open] != char: # found the first mismatch. Add points and stop looking at this line.
                    tot_points += POINTS[char]
                    break
    return tot_points


def part2(data):
    incomplete_lines = []
    for line in data:
        stack = []
        tot_score = 0
        for char in line:
            if char in BRACKET_PAIRS.keys():
                stack.append(char)
            elif char in BRACKET_PAIRS.values():
                most_recent_open = stack[-1]
                if BRACKET_PAIRS[most_recent_open] != char: # Corrupted line; should ignore for part 2
                    break
                else:
                    stack.pop()
        else: # did not encounter break, so this is an incomplete line that we need to "complete"
            while(len(stack) > 0):
                open_char = stack.pop()
                tot_score *= 5
                tot_score += POINTS_2[BRACKET_PAIRS[open_char]]
            incomplete_lines.append(tot_score)

