class Squid:
    def __init__(self, value):
        self.value = value
        self.flashed = 0

    def __repr__(self):
        return f'''{self.value}'''

    def __str__(self):
        return self.value

    def increase(self):
        self.value += 1
        if self.value > 9 and not self.flashed:
            self.to_flash()

    def to_flash(self):
        if not self.flashed:
            self.flashed = 1

    def flash(self):
        if self.flashed == 1:
            self.flashed = 2
            return True
        else:
            return False

    def reset(self):
        if self.flashed == 2:
            self.value = 0
            self.flashed = 0
            return True
        else:
            return False


