def fold(line, points):
    m = re.match(r'fold along ([xy])=(\d+)', line)
    value = int(m.group(2))
    if m.group(1) == 'x':
        fn = lambda p: p if p[0] < value else (value - (p[0] - value), p[1])
    else:
        fn = lambda p: p if p[1] < value else (p[0], value - (p[1] - value))
    return set(fn(point) for point in points)

