    for fold in folds:
        axis = fold[11]
        fold_num = int(fold[13:])

        if axis == 'y':
            for coordinate in coordinates:
                y = coordinate[1]
                if ((y - fold_num) * 2) >= 0:
                    coordinate[1] = y - ((y - fold_num) * 2)

        if axis == 'x':
            for coordinate in coordinates:
                x = coordinate[0]
                if ((x - fold_num) * 2) >= 0:
                    coordinate[0] = x - ((x - fold_num) * 2)

