def parse_input(lines: List[str]) -> (str, Dict[str, str]):
    return lines[0], {k.strip(): v.strip() for k, v in map(lambda l: l.split('->'), lines[2:])}


def part_1(template: str, insertion_dict: Dict[str, str], rounds: int) -> int:
