        raise NotImplementedError()


class LiteralValue(Packet):

    def parse(self, bits):
        value_bits = BitArray()
        while bits[0]:
            value_bits += bits[1:5]
            bits = bits[5:]
        value_bits += bits[1:5]
        bits = bits[5:]

        self._value = value_bits
        return bits

    @property
    def value(self):
        return self._value.uint


class Operator(Packet):

    def version_sum(self):
        sub_packets_sum = sum([p.version_sum() for p in self.sub_packets])
        return self.version + sub_packets_sum

    @property
    def value(self):
        values = [p.value for p in self.sub_packets]
        if self.type == 0:
            val = sum(values)
        elif self.type == 1:
            val = reduce(operator.mul, values)
        elif self.type == 2:
            val = min(values)
        elif self.type == 3:
            val = max(values)
        elif self.type == 5:
            val = 1 if values[0] > values[1] else 0
        elif self.type == 6:
            val = 1 if values[0] < values[1] else 0
        elif self.type == 7:
            val = 1 if values[0] == values[1] else 0

        return val

    def parse(self, bits):
        length_type = bits[0]
        if length_type:
            nb_sub_packets = bits[1:12].uint
            packets, remainder = self.parse_sub_packets_nb(bits[12:], nb_sub_packets)
        else:
            sub_packets_length = bits[1:16].uint
            packets, remainder = self.parse_sub_packets_length(bits[16:], sub_packets_length)

        self.sub_packets = packets
        return remainder

    def parse_sub_packets_nb(self, bits, nb_sub_packets):
        packets = []
        while len(packets) < nb_sub_packets:
            packet, remainder = parse(bits)
            packets.append(packet)
            bits = remainder
        return packets, remainder

    def parse_sub_packets_length(self, bits, sub_packets_length):
        packets = []
        nb_bits = 0
        remainder = bits
        while nb_bits < sub_packets_length:
            packet, remainder = parse(bits)
            nb_bits += len(bits) - len(remainder)
            packets.append(packet)
            bits = remainder
        return packets, remainder

