            if not length:
                deq.append(sum)
            else:
                if sum >= deq[length-1]:
                    deq.append(sum)
                if sum >= deq[0] and sum < deq[1]:
                    deq.popleft()
                    deq.appendleft(sum)
            sum = 0
        else:
            sum += int(calorie)

