from enum import IntEnum

class Move(IntEnum):
    ROCK = 0
    PAPER = 1
    SCISSORS = 2

class Game(IntEnum):
    WIN = 6
    DRAW = 3
    LOSE = 0


var_to_move = {"A": Move.ROCK,     "X": Move.ROCK,
               "B": Move.PAPER,    "Y": Move.PAPER,
               "C": Move.SCISSORS, "Z": Move.SCISSORS}

var_to_outcome = {"X": Game.LOSE, "Y": Game.DRAW, "Z": Game.WIN}


def play(them, us):
    if them == us:
        return Game.DRAW
    if Move((them + 1) % 3) == us:
        return Game.WIN
    return Game.LOSE


def deduce(them, outcome):
    if outcome == Game.DRAW:
        return them
    if outcome == Game.WIN:
        return Move((them + 1) % 3)
    if outcome == Game.LOSE:
        return Move((them + 2) % 3)


def part1(input):
    games = [(var_to_move[them], var_to_move[us]) for (them, us) in input]
    result = sum(play(them, us) + us + 1 for (them, us) in games)
    print(result)


def part2(input):
    games = [(var_to_move[them], var_to_outcome[us]) for (them, us) in input]
    games = [(them, deduce(them, outcome)) for (them, outcome) in games]
    result = sum(play(them, us) + us + 1 for (them, us) in games)
    print(result)


