from collections import deque
from typing import Deque, Any


def parse(filepath: str) -> tuple[list[Deque[Any]], list[list[int]]]:
    with open('year_2022_day_5.txt') as f:
        stack, instructions = f.read().strip().split('\n\n')

    heaps = map_heaps(stack)
    instructions = get_values(instructions)

    return heaps, instructions


def map_heaps(stack: str) -> list[Deque[Any]]:
    # making sure all of the rows are the same length
    stack = stack.splitlines()
    stack = [row.rjust(len(stack[-1])) for row in stack]

    # easiest way i could think of to map the heaps was based on
    # the index of the numbers at the bottom of the stack
    heaps = {
        i: deque([]) for i, n in enumerate(stack[-1]) if n.isdigit()
    }

    for line in stack[:-1]:
        for i in heaps:
            if line[i].isalpha():
                heaps[i].append(line[i])

    return list(heaps.values())


def get_values(instructions: str) -> list[list[int]]:
    return [
        [int(n) for n in re.findall(r'\d+', line)]
        for line in instructions.splitlines()
    ]


def move_crates(
    n: int,
    source: int,
    destination: int,
    heaps: list[Deque[Any]],
    part: int = 1
) -> None:

    if part == 1:
        for i in range(n):
            heaps[destination - 1].appendleft(heaps[source - 1].popleft())

    else:
        res = [heaps[source - 1].popleft() for _ in range(n)][::-1]
        heaps[destination - 1].extendleft(res)

    return


def run(filepath: str, part: int = 1) -> None:
    heaps, instructions = parse(filepath)
    for i, (n, source, destination) in enumerate(instructions):
        move_crates(n, source, destination, heaps, part=part)

    print(''.join((heap[0] for heap in heaps)))


