from collections import defaultdict

class FS:
    def __init__(self, content):
        self.fs = defaultdict(lambda: 0)
        self.loc = None
        for l in content:
            l = l.strip().split()
            if l[0] == "$":
                if l[1] == "cd" and l[2] != "..":
                    if not self.loc:
                        self.loc = (l[2],)
                    else:
                        self.loc = (*self.loc, l[2])
                elif l[1] == "cd" and l[2] == "..":
                    self.loc = self.loc[:-1]
            elif l[0].isnumeric():
                curr_l = self.loc
                while curr_l:
                    self.fs[curr_l] += int(l[0])
                    curr_l = curr_l[:-1]

    def dirs_sizeN(self, N):
        total = 0
        for dir, data in self.fs.items():
            if data <= N:
                total += data
        return total

    def min_dir_del(self):
        min_dir = None
        free = 70000000 - (self.fs[("/",)])
        for dir, data in self.fs.items():
            if not min_dir or (free+data >= 30000000 and data < min_dir):
                min_dir = data
        return min_dir

def main() -> int:
    with open('year_2022_day_7.txt') as f:
        content = f.readlines()   

    fs = FS(content)
    # Part 1:
    print(f'Part1: {fs.dirs_sizeN(100_000)}')
    # Part 2:
    print(f'Part2: {fs.min_dir_del()}')

if __name__ == "__main__":
    raise SystemExit(main())

from collections import defaultdict


def solve(part, useExample):
    filename = "exampleinput.txt" if useExample else "input.txt"

    dirs = defaultdict(int)

    with open('year_2022_day_7.txt') as openfileobject:
        lines = [l.strip() for l in openfileobject.readlines()]

    current_path = ''

    for row in lines[1:]:

        if row[0] == '$':
            if row[0:4] == '$ cd':
                if row[5:7] == '..':
                    current_path = "/".join(current_path.split("/")[:-1])
                    dirs[current_path] += 0
                else:
                    current_path = "/".join(current_path.split("/") + [row[5:]])
                    dirs[current_path] += 0
            elif row[0:4] == '$ ls':
                pass

        elif row[0:3] == 'dir':
            pass
        else:
            dirs[current_path] += int(row.split()[0])

    sorted_dirs = sorted(dirs.items(), key=lambda k: k[0].count('/'), reverse=True)
    summed = defaultdict(int)

    for key, val in sorted_dirs:
        paths = key.split('/')

        current_path = "/".join(paths[:len(paths)])
        summed[current_path] += val

        if current_path != '':
            parent_path = "/".join(paths[:len(paths) - 1])
            summed[parent_path] += summed[current_path]

    needed = 30000000 - (70000000 - summed[""])

    part1 = sum(val for val in summed.values() if val <= 100000)
    part2 = min(val for val in summed.values() if val >= needed)

    if part == 1:
        return part1

    if part == 2:
        return part2


