def trees_that_way(me, way):
    match way:
        case 'n': return [him for him in trees.keys() if him[0] < me[0] and him[1] == me[1]]
        case 's': return [him for him in trees.keys() if him[0] > me[0] and him[1] == me[1]]
        case 'w': return [him for him in trees.keys() if him[0] == me[0] and him[1] < me[1]]
        case 'e': return [him for him in trees.keys() if him[0] == me[0] and him[1] > me[1]]

def who_blocks_me(me, them): return ([him for him in them if (trees[him] >= trees[me])])

def distance_between(me, him): return abs(me[0] - him[0]) + abs(me[1] - him[1])

def scenic_score(me):
    score = 1
    for way in ('n','s','w','e'):
        them = trees_that_way(me, way)
        blockers = who_blocks_me(me, them)
        if blockers == []: score *=  len(them)
        elif blockers != []: score *=  min(distance_between(me, him) for him in blockers)
    return score

