    s1, s2 = rope[i], rope[i+1]
    if s1.distance_to(s2) >= 2:
      dx, dy = s1 - s2
      if abs(dx) > 1:  dx //= abs(dx)
      if abs(dy) > 1:  dy //= abs(dy)
      rope[i+1] = s2 + V(dx, dy)
  return rope    


def solve(puzzle, rope_length):
