        dx, dy = knots[i-1][0] - knots[i][0], knots[i-1][1] - knots[i][1]
        if abs(dx) > 1 or abs(dy) > 1:
          knots[i][0] += np.sign(dx)
          knots[i][1] += np.sign(dy)
      tailPos.add(tuple(knots[-1]))
  return len(tailPos)

