    print(simulate(10))

def simulate(rope_length):
    knot_positions = []
    for i in range(rope_length):
        knot_positions.append(np.array([0,0]))
    tail_visited_positions = set()
    tail_visited_positions.add(tuple(knot_positions[-1]))
    with open('year_2022_day_9.txt', 'r', encoding="utf-8") as f:
        lines = f.readlines()
    for line in lines:
        head_moves = parse_head_moves(line)
        for head_move in head_moves:
            knot_positions[0] = knot_positions[0] + head_move
            for i in range(1, len(knot_positions)):
                if not_touching(knot_positions[i-1], knot_positions[i]):
                    knot_positions[i] = move_trailing_knot(knot_positions[i-1], knot_positions[i])
            tail_visited_positions.add(tuple(knot_positions[-1]))
    return len(tail_visited_positions)

def parse_head_moves(line):
    direction, quantity = line.strip().split()
    moves = []
    direction_moves = {'R':np.array([1,0]), 'L':np.array([-1,0]), 'U':np.array([0,1]), 'D':np.array([0,-1])}
    for i in range(int(quantity)):
        moves.append(direction_moves[direction])
    return moves

def not_touching(pos1, pos2):
    abs_distance = np.absolute(pos1 - pos2)
    return np.any(abs_distance > 1)

def move_trailing_knot(leading_pos, trailing_pos):
    move = leading_pos - trailing_pos
    move[move > 0] = 1
    move[move < 0] = -1
    return trailing_pos + move

