# https://adventofcode.com/2022/day/11

import heapq
import re
from functools import reduce
from itertools import chain
from operator import attrgetter, mul

F = 'day11_inp.txt'

NUM = re.compile(r'(\d+)')
OP  = re.compile(r'Operation: new = (old [\+\-\*] (\d+|old))')
DIV = re.compile(r'Test: divisible by (\d+)')
TR  = re.compile(r'If true: throw to monkey (\d+)')
FA  = re.compile(r'If false: throw to monkey (\d+)')
PATTERNS = (OP, DIV, TR, FA)

ROUNDS_PT1 = 20
ROUNDS_PT2 = 10000

N = 2

class Monkey:
    def __init__(self, items, op, div, tr, fa):
        self.items = items
        self.op = op # 'new = old [+-*] num'
        self.div = div
        self.tr = tr
        self.fa = fa
        self.inspections = 0

    def inspectAndRedistributeItems(self):
        self.inspections += len(self.items)

        for item in self.items:
            item = self.inspectItem(item)
            if item % self.div == 0:
                yield item, self.tr
            else:
                yield item, self.fa

        self.clearItems()

    def clearItems(self):
        self.items = []

    def addItem(self, item):
        self.items.append(item)

def proc_inp(f):
    monkeys = {}

    with open('year_2022_day_11.txt') as f:
        try:
            line = next(f)
        except StopIteration: # F is empty
            return

        f = chain((line,), f)

        extract = lambda pattern: re.search(pattern, next(f)).group(1)

        while True:
            i = int(re.search(NUM, next(f)).group())
            assert i not in monkeys
            items = list(map(int, re.findall(NUM, next(f))))
            op, div, tr, fa = tuple(map(extract, PATTERNS))
            monkeys[i] = Monkey(
                items,
                op,
                int(div),
                int(tr),
                int(fa))
            try:
                next(f) # space
            except StopIteration: # eof
                break

    return monkeys

def solve(monkeys, rounds):
    idxs = sorted(monkeys.keys())
    for _ in range(rounds):
        for idx in idxs:
            monkey = monkeys[idx]
            for item, j in monkey.inspectAndRedistributeItems():
                monkeys[j].addItem(item)

    n_largest = heapq.nlargest(
        n=N,
        iterable=monkeys.values(),
        key=attrgetter('inspections'))

    n_largest = map(attrgetter('inspections'), n_largest)

    return reduce(mul, n_largest)

def solve_pt1():
    monkeys = proc_inp(F)
    def inspectItem(self, old):
        return eval(self.op) // 3 # (old [+-*] num) // 3
    Monkey.inspectItem = inspectItem # monkey patching Monkey
    return solve(monkeys, ROUNDS_PT1)

def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)

def lcm(a, b):
    return (a * b) // gcd(a, b)

def solve_pt2():
    monkeys = proc_inp(F)
    LCM = reduce(lcm, map(attrgetter('div'), monkeys.values()))
    def inspectItem(self, old):
        return eval(self.op) % LCM # new = old [+-*] num
    Monkey.inspectItem = inspectItem # monkey patching Monkey
    return solve(monkeys, ROUNDS_PT2)

print(solve_pt1())
print(solve_pt2())

