    lst = [one, two]
    while enum < (length := min(len(one), len(two))):
        val_one, val_two = one[enum], two[enum]
        if val_one == val_two:
            enum += 1
            if enum == length:
                return len(one) < len(two)
        else:
            type_one, type_two = type(val_one), type(val_two)
