I = lambda x:isinstance(x,int)
L = lambda x:isinstance(x,list)

def cmp(l,r):
  if I(l) and I(r):
    if l<r: return -1
    return l>r
  if L(l) and L(r):
    for i in range(min(len(l),len(r))):
      c = cmp(l[i],r[i])
      if c: return c
    return cmp(len(l),len(r))
  if I(l) and L(r):
    return cmp([l],r)
  if L(l) and I(r):
    return cmp(l,[r])

