def cmp(left, right):
    match left, right:
        case int(), list():
            return cmp([left], right)
        case list(), int():
            return cmp(left, [right])
        case int(), int():
            return left - right
        case list(), list():
            for i, j in zip(left, right):
                if (r := cmp(i, j)) != 0:
                    return r
            return cmp(len(left), len(right))


