def get_digits(line):
    digit_dict = {}
    letters = list(line.strip())
    for idx, letter in enumerate(letters):
        if letter.isdigit():
            digit_dict[idx] = int(letter)
    for word in SPELLED_DIGIT_MAP.keys():
