from dataclasses import dataclass
from lib import skipWhitespace

@dataclass
class Card:
    winningNums: set
    elvesNums: set
    instances: int

def parse(input: str) -> list:
    cards = []
    for line in input.splitlines():
        cards.append(Card(set(), set(), 1))
        readingWinning = True
        for item in skipWhitespace(line):
            if item == "Card" or ':' in item:
                continue
            elif item == '|':
                readingWinning = False
            else:
                if readingWinning:
                    cards[-1].winningNums.add(int(item))
                else:
                    cards[-1].elvesNums.add(int(item))
    return cards

def process(input: str) -> (int, int):
    part1 = 0
    part2 = 0
    cards = parse(input)
    for i, card in enumerate(cards):
        inter = card.winningNums.intersection(card.elvesNums)
        numMatches = len(inter)
        points = (1 << (numMatches - 1)) if numMatches > 1 else numMatches
        part1 += points
        for instance in range(card.instances):
            for nextCard in range(i + 1, i + numMatches + 1):
                cards[nextCard].instances += 1
        part2 += card.instances
    return (part1, part2)

with open('year_2023_day_4.txt', 'r') as f:
    part1, part2 = process(f.read())
    print("Part1:", part1)
    print("Part2:", part2)

