            while (c := (next_start := next_start + cycle) % cyc not in (offset, offset % cyc)) or not nxt[1:]:
                if not c:
                    nxt.append(next_start)
            recurse(deepcopy(keys), deepcopy(paths), nxt[0], nxt[1] - nxt[0])
    return min(best)

