def binom_with_neg(n, k):
    assert type(n) == int and type(k) == int and k >= 0
    if k > n and n >= 0:
        return 0
    sign = 1
    if n < 0:
        sign = (-1)**k
        n = -n + k - 1
    return int(sign * (fact(n) / (fact(k) * fact(n - k))))

def get_nth(n, firsts):
    s = 0
    for i, f in enumerate(firsts):
        s += f * binom_with_neg(n, i) # gregory-newton interpolation
    return s

