                counter += 1
                plus_row = len([x for x in rows_to_expand if x < row])*(expansion-1)
                plus_col = len([x for x in cols_to_expand if x < col])*(expansion-1)
                galaxies[counter] = (row + plus_row, col + plus_col)
    distances = {}
    for key, value in galaxies.items():
        for num in range(key+1,len(galaxies)+1):
            distances[(key, num)] = abs(galaxies[key][0]-galaxies[num][0])+ abs(galaxies[key][1]-galaxies[num][1])
    res = 0
    for val in distances.values():
        res += val
    res
    return res

