def tilt(height, width, round, square, dx, dy):
    moved = True
    while moved:
        moved = False
        for rock in round:
            x,y = rock
            x += dx
            y += dy
            if y < 0 or x < 0:
                continue
            if y >= height or x >= width:
                continue
            if (x,y) in square or (x,y) in round:
                continue
            round.remove(rock)
            round.add((x,y))
            moved = True
    return round

