def neighbors(x,y):
    for dx,dy in ((0,1),(1,0),(0,-1),(-1,0)):
        nx,ny = x+dx,y+dy
        if 0 <= nx < width and 0 <= ny < height:
            if grid[ny][nx] in '.<>^v':
