        for k, v in conjunctions.items():
            heapify(queue := [(0, k, {k})])
            while queue:
                steps, current, seen = heappop(queue)
                if current in conjunctions and k != current: v[current] = min(v.get(current, 0), steps); continue
                for e, nxt in enumerate(adj(*current)):
