def calc_1(input: str) -> int:
    return sum([int(match.group(1)) * int(match.group(2)) for match in re.finditer("mul\\((\\d+),(\\d+)\\)", input)])

def calc_2(input: str) -> int:
    first_pattern = ".+?(?=don't\\(\\))"
    second_pattern = "(?<=do\\(\\))(.+?)(?=don't\\(\\)|$)"
    first_segment = re.findall(first_pattern, input, re.DOTALL)[0]
    segments = re.findall(second_pattern, input[len(first_segment):], re.DOTALL)
    return calc_1(first_segment) + sum([calc_1(s) for s in segments])

