                    elif ternary_ops[n] == '2':
                        temp_res = int(str(vals[n]) + str(vals[n + 1]))
                elif n > 0 and n < len(ternary_ops):
                    if ternary_ops[n] == '0':
                        temp_res = temp_res + int(vals[n + 1])
                    elif ternary_ops[n] == '1':
                        temp_res = temp_res * int(vals[n + 1])
