def r1(n):
    return [1]

def r2(n):
    s = str(n)
    h = len(s) // 2
    l = int(s[:h]) if h > 0 else 0
    r = int(s[h:]) if h < len(s) else 0
    return [l, r]

def r3(n):
    return [n * 2024]

rule_cache = {}
def rules(n):
    if n in rule_cache:
        return rule_cache[n]
    if n == 0:
        result = r1(n)
    elif len(str(n)) % 2 == 0:
        result = r2(n)
    else:
        result = r3(n)
    rule_cache[n] = result
    return result

