import sys
from functools import cache


def calc(n):
    length = len(str(n))
    if n == 0:
        return 1
    elif length % 2 == 0:
        l, r = int(str(n)[: length // 2]), int(str(n)[length // 2 :])
        return (l, r)
    else:
        return n * 2024


@cache
def split(n, blinks):
    _n = n
    splits = 0
    for i in range(blinks):
        c = calc(_n)
        if isinstance(c, int):
            _n = c
        if isinstance(c, tuple):
            splits += 1
            _n = c[0]
            splits += split(c[1], blinks - i - 1)
    return splits


