from z3 import *
import re

def solve(a, b, c, d, e, f):
    o = Optimize()
    x, y = Ints('x y')
    o.add(c == a * x + b * y)
    o.add(f == d * x + e * y)
    tokens = Int('tokens')
    o.add(tokens == 3 * x + y)
    o.minimize(tokens)
    if o.check() == unsat:
        return 0
    res = o.model()[tokens]
    return res.as_long()

