def cheat_bfs(grid, costs, start, maxcount, target):
    queue = deque([(start, False, maxcount, 0)])
    seen, saved = set(), {}
    while queue:
        loc, cheat, count, dist = queue.popleft()
        if (loc, cheat) in seen or count<0: continue
        seen.add((loc, cheat))
        if cheat:
            if grid[loc]!='#' and costs[loc]+dist<costs[start]:
