def nwsize_dq(conns):
    q = deque()
    sol = None
    seen = set()
    q.extendleft((n,) for n in conns.keys())

    while q:
        if (nw := q.pop()) in seen:
            continue
        seen.add(nw)

        cand_lst = set.intersection(*(conns[n] for n in nw))

        if cand_lst:
